import { useEffect, useState } from "react";
import {
  getPatients,
  addPatient,
  getAppointments,
  addAppointment
} from "../api";

import Sidebar from "./Sidebar";
import Search from "./Search";
import Prescription from "./Prescription";

import jsPDF from "jspdf";
import html2canvas from "html2canvas";

export default function Dashboard() {
  const [page, setPage] = useState("dashboard");

  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);

  const [patientForm, setPatientForm] = useState({
    name: "",
    phone: "",
    age: ""
  });

  const [appointmentForm, setAppointmentForm] = useState({
    patient_id: "",
    date: ""
  });

  const [searchPatientId, setSearchPatientId] = useState("");

  const doctorId = localStorage.getItem("userId");

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const patientsData = await getPatients();
    const appointmentsData = await getAppointments();

    setPatients(patientsData || []);
    setAppointments(appointmentsData || []);
  };

  // ================= ADD PATIENT =================
  const handleAddPatient = async () => {
    await addPatient({
      name: patientForm.name,
      phone: patientForm.phone,
      age: Number(patientForm.age)
    });

    setPatientForm({ name: "", phone: "", age: "" });
    loadData();
  };

  // ================= ADD APPOINTMENT =================
  const handleAddAppointment = async () => {
    await addAppointment({
      patient_id: Number(appointmentForm.patient_id),
      doctor_id: Number(doctorId),
      date: new Date(appointmentForm.date).toISOString()
    });

    setAppointmentForm({ patient_id: "", date: "" });
    loadData();
  };

  // ================= FILTER APPOINTMENTS =================
  const filteredAppointments = searchPatientId
    ? appointments.filter(
        (a) => a.patient_id === Number(searchPatientId)
      )
    : appointments;

  // ================= PRINT =================
  const handlePrint = () => {
    window.print();
  };

  // ================= PDF =================
  const handleDownloadPDF = async (id) => {
    const element = document.getElementById(id);
    const canvas = await html2canvas(element);
    const imgData = canvas.toDataURL("image/png");

    const pdf = new jsPDF();
    pdf.addImage(imgData, "PNG", 10, 10, 180, 0);
    pdf.save("data.pdf");
  };

  return (
    <div style={{ display: "flex" }}>
      <Sidebar setPage={setPage} />

      <div style={{ padding: "20px", width: "100%" }}>
 <h1 className="text-3xl font-bold text-blue-600">
    Tailwind is Working 🚀
  </h1>
        {/* ================= DASHBOARD ================= */}
        {page === "dashboard" && (
          <>
            <h2>Dashboard Overview</h2>
            <p>Total Patients: {patients.length}</p>
            <p>Total Appointments: {appointments.length}</p>
          </>
        )}

        {/* ================= PATIENTS ================= */}
        {page === "patients" && (
          <>
            <h2>Patients</h2>

            <input
              placeholder="Name"
              value={patientForm.name}
              onChange={(e) =>
                setPatientForm({ ...patientForm, name: e.target.value })
              }
            />

            <input
              placeholder="Phone"
              value={patientForm.phone}
              onChange={(e) =>
                setPatientForm({ ...patientForm, phone: e.target.value })
              }
            />

            <input
              placeholder="Age"
              value={patientForm.age}
              onChange={(e) =>
                setPatientForm({ ...patientForm, age: e.target.value })
              }
            />

            <button onClick={handleAddPatient}>Add Patient</button>

            <br /><br />

            <button onClick={handlePrint}>Print</button>
            <button onClick={() => handleDownloadPDF("patients-section")}>
              Download PDF
            </button>

            <div id="patients-section">
              {patients.map((p) => (
                <div key={p.id}>
                  ID: {p.id} | {p.name} | {p.phone} | Age: {p.age}
                </div>
              ))}
            </div>
          </>
        )}

        {/* ================= APPOINTMENTS ================= */}
        {page === "appointments" && (
          <>
            <h2>Appointments</h2>

            <select
              value={appointmentForm.patient_id}
              onChange={(e) =>
                setAppointmentForm({
                  ...appointmentForm,
                  patient_id: e.target.value
                })
              }
            >
              <option value="">Select Patient</option>
              {patients.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name}
                </option>
              ))}
            </select>

            <input
              type="datetime-local"
              value={appointmentForm.date}
              onChange={(e) =>
                setAppointmentForm({
                  ...appointmentForm,
                  date: e.target.value
                })
              }
            />

            <button onClick={handleAddAppointment}>
              Add Appointment
            </button>

            <br /><br />

            {/* FILTER BY PATIENT ID */}
            <input
              placeholder="Search by Patient ID"
              value={searchPatientId}
              onChange={(e) => setSearchPatientId(e.target.value)}
            />

            <button onClick={handlePrint}>Print</button>
            <button onClick={() => handleDownloadPDF("appointments-section")}>
              Download PDF
            </button>

            <div id="appointments-section">
              {filteredAppointments.map((a) => (
                <div key={a.id}>
                  Patient ID: {a.patient_id} |{" "}
                  {new Date(a.date).toLocaleString()}
                </div>
              ))}
            </div>
          </>
        )}

        {/* ================= SEARCH ================= */}
        {page === "search" && <Search />}

        {/* ================= PRESCRIPTION ================= */}
        {page === "prescription" && <Prescription />}

      </div>
    </div>
  );
}
